
import base64, os, glob, shutil

AGENT = "/opt/polymarket-agent"

# Write fixed autotrader
data = base64.b64decode("").decode()
with open(f"{AGENT}/autotrader.py", "w") as f:
    f.write(data)
print(f"Written: {len(data)} chars")

# Nuke ALL pycache
removed = 0
for root, dirs, files in os.walk(AGENT):
    for fname in files:
        if fname.endswith(".pyc"):
            try: os.remove(os.path.join(root, fname)); removed += 1
            except: pass
    for d in list(dirs):
        if d == "__pycache__":
            try: shutil.rmtree(os.path.join(root, d)); removed += 1
            except: pass
print(f"Cleared {removed} cache items")

# Verify
with open(f"{AGENT}/autotrader.py") as f:
    c = f.read()
has_enddate = "_days_left < 3" in c
has_blacklist = "_THESIS_BLACKLIST" in c
has_keywords = "connecticut huskies" in c
print(f"End-date guard: {has_enddate}")
print(f"Condition blacklist: {has_blacklist}")
print(f"Keyword guard: {has_keywords}")
if has_enddate and has_blacklist and has_keywords:
    print("ALL 3 GUARDS CONFIRMED — SAFE TO RESTART")
else:
    print("WARNING: some guards missing")
